-- Primeiro deletar as presenças da aula 01/03 (numero=1)
DELETE FROM presencas WHERE aulaId = (SELECT id FROM aulas WHERE data = '01/03' LIMIT 1);

-- Deletar a aula 01/03
DELETE FROM aulas WHERE data = '01/03';

-- Renumerar as aulas: cada aula tem seu numero decrementado em 1
UPDATE aulas SET numero = numero - 1 WHERE numero > 1 ORDER BY numero ASC;

